    ('MUS-Z 115', 'JAZZ IMPROVISATION AND THEORY', '14530', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'MA 006', 'Oliver Nelson', 5, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'This course is designed for the student who has an interest in jazz and wants to learn jazz improvisation and theory skills that can enhance their personal musical expression. Students will expand their knowledge of jazz through an understanding of its mechanics and practical implementation.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 120', 'MUSIC IN MULTIMEDIA', '4333', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SM 373', 'Christopher Renk', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Overview of multimedia elements for interactive environments and linear media. Introduction to digital media including animation, audio, video, and images. Audio techniques including sound synchronization with cue points, loops, digital signal processing effects, mixing, and conversions using a waveform editor.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 120', 'MUSIC IN MULTIMEDIA', '8559', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SM 373', 'Christopher Renk', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Overview of multimedia elements for interactive environments and linear media. Introduction to digital media including animation, audio, video, and images. Audio techniques including sound synchronization with cue points, loops, digital signal processing effects, mixing, and conversions using a waveform editor.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 120', 'MUSIC IN MULTIMEDIA', '7176', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Eric Lindsay', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Overview of multimedia elements for interactive environments and linear media. Introduction to digital media including animation, audio, video, and images. Audio techniques including sound synchronization with cue points, loops, digital signal processing effects, mixing, and conversions using a waveform editor.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 120', 'MUSIC IN MULTIMEDIA', '12941', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Eric Lindsay', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Overview of multimedia elements for interactive environments and linear media. Introduction to digital media including animation, audio, video, and images. Audio techniques including sound synchronization with cue points, loops, digital signal processing effects, mixing, and conversions using a waveform editor.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 120', 'MUSIC IN MULTIMEDIA', '4334', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SM 373', 'Jeremy Podgursky', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Overview of multimedia elements for interactive environments and linear media. Introduction to digital media including animation, audio, video, and images. Audio techniques including sound synchronization with cue points, loops, digital signal processing effects, mixing, and conversions using a waveform editor.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 125', 'DISCOVERING YOUR CREATIVE IMPULSE', '34042', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SM 149C', 'Debbi Ponella', 10, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Designed for students to gain insight into, and facility with, one''s own creativity through the study of music and its relationship to other disciplines. With the foundational belief that all humans are inherently creative, this course offers students a space to study, practice, and express their unique voices.', ARRAY[]::TEXT[], NULL),
    ('MUS-Z 130', 'MUSICAL PERFORMANCE CONTEXTS', '6628', 'Class Status', 'Tu Tuesday 6:40 PM–8:20 PM', 'SM 015', 'Constance Cook, Aaron Riedford', 4, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'An introduction to music listening through weekly in-class performances. Students have an opportunity to interact with instrumentalists, singers, dancers, choreographers, conductors, and composers. Additional study of historical and musical contexts for the performances seen during class. Musical styles include classical, rock, jazz, and world music. Credit given for only one of Z100 and Z130.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 130', 'MUSICAL PERFORMANCE CONTEXTS', '9660', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 8:00 AM–2:30 PM', 'SM 015', 'Kyle Adams', 6, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'An introduction to music listening through weekly in-class performances. Students have an opportunity to interact with instrumentalists, singers, dancers, choreographers, conductors, and composers. Additional study of historical and musical contexts for the performances seen during class. Musical styles include classical, rock, jazz, and world music. Credit given for only one of Z100 and Z130.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 190', 'JAZZ FOR LISTENERS', '6668', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'MA 404', 'Oliver Nelson', 0, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'An examination of the components of jazz, how to listen to jazz, and how to relate jazz to the social/cultural environment in which it was created. Class lectures/discussions enhanced with live performances and videos of major artists such as Louis Armstrong, Charlie Parker, Miles Davis, and John Coltrane.', ARRAY['IUB GenEd A&H credit
Class uses IU eTexts'], NULL),
    ('MUS-Z 201', 'HISTORY OF ROCK AND ROLL MUSIC', '4737', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 013', 'Andrew Hollinden', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'A survey of the major trends, styles, and genres of rock music from the earliest recordings to the present day, focusing on the work of the artist and groups who have proven to be of the most enduring significance.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 203', 'HISTORY OF ROCK ''N'' ROLL MUSIC III', '5518', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 013', 'Andrew Hollinden', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'A survey of 1970s-80s rock and its continuation into the 90s, as well as its impact on the expansion of popular music today. Genres include: Prog Rock, Hard Rock, Metal, Glam Rock, Singer-Songwriters, Krautrock, Reggae, Jazz Fusion, Disco, Funk, Rap, Punk Rock, New Wave, Alternative Rock, Grunge, and more.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 204', 'WOMEN MUSICIANS', '6629', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'RA B109', 'Constance Cook, Meredith Michael', 15, NULL, 'Lecture', '3', 'SPRUCE HALL', ARRAY[]::TEXT[], 'This class will explore the various roles women have played, and continue to play, in the world of music. Four distinct areas in which women engage are patronage, performance, composition, and education. Previous musical training is not required.', ARRAY['IUB GenEd S&H credit
Class uses IU eTexts'], NULL),
    ('MUS-Z 205', 'THE HISTORY OF MUSIC PRODUCTION', '10448', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Paul Mahern', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'From Edison to digital streaming, this course explores the evolution of recorded music through artistic innovation and technological advancements. Students will examine how artists, producers, record labels, and A&R professionals shaped music production, influencing genres, driving trends, and transforming the sound and cultural impact of recorded music across different eras.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('MUS-Z 208', 'HISTORY OF PUNK ROCK', '8882', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WB WEB', 'Paul Mahern', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Punk rock is rock taken to its most ferocious conclusion. In this class we investigate what happens when musicians choose the guitar as a weapon against boredom and rigged systems. We see the elements of minimalism, politics, and cynicism form one of the most influential musical movements of modern times.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 209', 'AMERICAN INDIE ROCK', '14531', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'SM C141', 'Jeremy Podgursky', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'There is a rich, diverse realm of independent pop music that sometimes artistically eclipses major label recording artists. This course explores the indie rock scene in America as an exercise in expression as well as an example of an economic system that is outside of these labels.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 210', 'WOMEN IN POPULAR MUSIC', '33967', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SM C141', 'Mandy Smith', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Women in popular music from the 20th century to today are the focus of this course. Students will be exposed to many genres of popular music through representative artists and their songs. Connections between popular music and issues concerning gender, sexuality, identity, race, age, and politics will be explored.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 211', 'MUSIC THEORY II', '4582', 'Closed', 'MW Monday, Wednesday 10:25 AM–11:25 AM', 'MC 036', 'Gabriel Lubell', 0, NULL, 'Lecture', '3', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Overview of part writing, musical form, harmonic analysis, and modulation.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 213', 'LATIN AMERICAN AND LATINO POPULAR MUSIC AND CULTURE', '7722', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SM 344', 'Javier Leon', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Latin American and Latino popular music genres, their historical and cultural contexts, and their impact in the United States. Activities outside of class may be scheduled.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 213', 'LATIN AMERICAN AND LATINO POPULAR MUSIC AND CULTURE', '34462', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 9:00 AM–4:00 PM', 'SM 344', 'Sergio Ospina Romero', 6, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Latin American and Latino popular music genres, their historical and cultural contexts, and their impact in the United States. Activities outside of class may be scheduled.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 226', 'SUPERHEROES: MUSIC IN CINEMA', '12602', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SM C141', 'Daniel Bishop', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'This course is an exploration of the role of music in the Marvel and DC cinematic franchises. It will study the genre of the superhero movie, and the ways in which this genre draws upon the film soundtrack as an aesthetic, cultural, and commercial medium.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 250', 'CHORAL MASTERWORKS', '11496', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SM 344', 'Constance Cook, Aaron Riedford', 2, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Introduction to the masterpieces of choral music through examination of musical, historical and cultural contexts. Study of selected oratorios, masses, requiems, passions, choral symphonies, choral music outside the Western art tradition, and music for glee clubs, show choirs, and vocal jazz groups. Class lectures/discussions enhanced with live performances.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 260', 'MUSIC IN AMERICAN SOCIETY', '4314', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'RA B109', 'Scott Grieb', 0, NULL, 'Lecture', '3', 'SPRUCE HALL', ARRAY[]::TEXT[], 'Music in the United States: its history and place in society from the earliest musical activities to some of its many present incarnations. Native American music, sacred and secular music in the New World to c.1800, music in the church, home and concert hall in the nineteenth century, African-American music, and various twentieth-century traditional popular and classical genres and styles.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 261', 'MUSIC AND COMMUNITY ENGAGEMENT I', '34040', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SM 267', 'Alissa Guntren, Daniel Cueto', 2, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'An introduction to concepts and practices that connect music to communities. The course focuses on community engagement practices and ways in which music impacts lives. Areas covered include: social role of the arts in society; professional and amateur involvement, and the role of cultural organizations in connecting music to communities.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 264', 'MUSIC AND VIDEOGAMES', '9026', 'Closed', 'MW Monday, Wednesday 6:40 PM–7:55 PM', 'WB WEB', 'Alex Ostergard', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An introduction to videogame music with analysis of its musical elements. The class will listen to and watch videogames and discuss scholarly viewpoints on videogame music. Connections to popular and other musics will be covered. The musical content of videogames will be discussed objectively. No prior musical knowledge is required.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 265', 'AMERICAN COUNTRY MUSIC', '6477', 'Closed', 'MW Monday, Wednesday 1:55 PM–2:45 PM', 'RA B111 WB WEB', 'Scott Grieb', 0, NULL, 'Lecture', '3', 'SPRUCE HALL, WEB-BASED CLASS', ARRAY[]::TEXT[], 'A listening-based survey of American country music from the 1920s to the present. Various musical styles and contributions of country music artists. Also considered are topics such as country music and race, religion, and working-class culture.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 270', 'MUSIC OF WAR AND PEACE', '11198', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SM C141', 'Constance Cook', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Examination of the musical output of composers who were (or are) committeed to memorializing and protesting war and calling for peace. Importance of music on this topic throughout western history, with emphasis on the 20th and 21st centuries including classical and popular music traditions.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 280', 'MUSIC OF THE SILK ROAD', '6630', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'MC 036', 'Dena El Saffar', 0, NULL, 'Lecture', '3', 'MUSICAL ARTS CENTER', ARRAY[]::TEXT[], 'Historical and current authentic music traditions of the Silk Road and their impact on music of today. The Silk Road was the network of trade routes that connected East Asia to the Mediterranean for almost 2000 years. It was the source of important cultural exchanges between the East and the West.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 281', 'EAST-WEST ENCOUNTERS IN MUSIC', '11497', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SM 015', 'Gabriel Lubell', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Examination of interaction and communication between two cultural realms conditionally defined as East and West. In this course, East is understood as the region including countries of the Middle East and Central Asia, and West is defined as Europe and the United States. The class looks in both Eastern and Western directions and explores hybridity of styles and genres in both domains and the impact of each area on the other.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 282', 'MUSIC OF RUSSIA', '30116', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SM C141', 'Alexis Witt, Constance Cook', 3, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'An introduction to Russian music, presenting an overview of its principal genres and styles, as well as of the major Russian composers and their musical works. Repertoire will include examples from composed music, folk music, sacred music, rock, pop music, and jazz.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 283', 'POPULAR MUSIC OF EUROPE AND ASIA', '8562', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'WB WEB', 'Hilary Finchum-Sung', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This class introduces styles and genres of popular music in Europe and Asia in relation to their cultural, historical, and geographic origins. It discusses the impact of American pop music while focusing on the unique forms of popular music that are based on the re-imagination of the local music traditions.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 284', 'MUSIC IN GLOBAL CINEMA', '10380', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'SM C141', 'Daniel Bishop', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'An introduction to the use of music in a wide variety of global films. Basic concepts of film music analysis and study of films organized by geographical units (India, East Asia, Africa, Latin America, Iran), including a unit on political film and music documentaries. Introduction to the soundtrack of each film and its roots in musical culture. Emphasis on writing assignments and in-class presentations.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 287', 'MUSICAL CREATIVITY IN DIVERSE CULTURES', '12603', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SM C141', 'Constance Cook', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'This course explores how musical creativity is perceived and practiced in cultures throughout the world. It investigates the forces that shape the musical products and processes of individuals from these diverse cultures. This course will explore vernacular and art music forms from within the United States and worldwide.', ARRAY['IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 288', 'VIDEOGAME MUSIC IN WORLD CULTURES', '14749', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'SM 242', 'Constance Cook, Meredith Michael', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Students will apply music appreciation paradigms to videogame music stemming from cultures around the world. Imperialism, colonization, and economic factors are all observable in the convergent media of videogames and will be covered. Informed by diverse perspectives, students will engage with problems in media such as representation and appropriation.', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit'], NULL),
    ('MUS-Z 290', 'REMIXING', '9672', 'Class Status', 'TuTh Tuesday, Thursday 3:10 PM–4:40 PM', 'WB WEB', 'Eric Lindsay', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Project-based course focused on both compositional and audio production skills. Includes discussion of concepts, techniques, and legal issues shaping current remixing culture.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('MUS-Z 315', 'MUSIC FOR FILM', '6631', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'MA 454', 'Christopher Renk', 27, NULL, 'Lecture', '3', 'MUSIC ADDITION', ARRAY[]::TEXT[], 'A stylistic and analytic survey of music for moving pictures, concentrating on American and English narrative films.', ARRAY[]::TEXT[], NULL),
    ('MUS-Z 361', 'INTRODUCTION TO MIDI AND COMPUTER MUSIC', '6279', 'Class Status', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'SM 373', 'Chi Wang', 1, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Modest working knowledge of personal computers. Basics of the Musical Instrument Digital Interface system, its software, and the instruments commonly used with desktop MIDI workstations (synthesizers, digital samplers). MIDI sequencing, digital audio editing, and principles of digital synthesis. The course is intended for those with little prior technical training.', ARRAY[]::TEXT[], NULL),
    ('MUS-Z 361', 'INTRODUCTION TO MIDI AND COMPUTER MUSIC', '4740', 'Closed', 'MW Monday, Wednesday 10:25 AM–11:15 AM', 'SM 373', 'John Gibson', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'Modest working knowledge of personal computers. Basics of the Musical Instrument Digital Interface system, its software, and the instruments commonly used with desktop MIDI workstations (synthesizers, digital samplers). MIDI sequencing, digital audio editing, and principles of digital synthesis. The course is intended for those with little prior technical training.', ARRAY[]::TEXT[], NULL),
    ('MUS-Z 401', 'THE MUSIC OF THE BEATLES', '10190', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SM 015', 'Gabriel Lubell', 60, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'An in-depth, song-by-song look at the music, lives, and times of the Beatles. The course focuses on the music and is aimed at heightening student listening skills as well as fostering a deeper appreciation for the Beatles'' recordings.', ARRAY[]::TEXT[], NULL),
    ('MUS-Z 402', 'MUSIC OF FRANK ZAPPA', '8884', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'SM 350', 'Andrew Hollinden', 0, NULL, 'Lecture', '3', 'SIMON MSC LBR REC', ARRAY[]::TEXT[], 'A detailed survey of the musical career of rock''s most avant-garde composer. Traces Zappa''s creative output from his early days through his solo projects, his "big band" period, his orchestral productions, and finally his groundbreaking work with the Synclavier. All of Zappa''s commercially released albums are discussed.', ARRAY[]::TEXT[], NULL),
    ('MUS-Z 710', 'NON-MUSIC MAJOR PERFORMANCE ELECTIVE', '2687', 'Class Status', NULL, NULL, 'Otis Murphy, Andrew Lamoureux', 6, NULL, 'Lecture', '3–4', NULL, ARRAY[]::TEXT[], 'Non-music major performance elective for graduate students.', ARRAY[]::TEXT[], NULL),
