    ('NAIS-A 150', 'INTRODUCTION TO NATIVE AMERICAN AND INDIGENOUS STUDIES', '32914', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 206', 'Liza Black', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to Native American and indigenous cultures, literature, history, arts, values, life-ways, spirituality, and social and political institutions. Focuses on global and hemispheric elements including North America.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('NAIS-A 400', 'TOPICS IN NATIVE AMERICAN AND INDIGENOUS STUDIES', '32817', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:20 PM', 'BH 106', 'Andrea Sullivan-Clarke', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores particular themes, topics and problems that are of general import to Native American and Indigenous cultures. Topics and aspects will vary, but will usually be broad subjects that cut across fields, regions, periods and cultures. Particular attention will be given to Indigenous expressions of knowledge.', ARRAY[]::TEXT[], NULL),
    ('NAIS-A 500', 'GRADUATE TOPICS IN NATIVE AMERICAN AND INDIGENOUS STUDIES', '32818', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:20 PM', 'BH 106', 'Andrea Sullivan-Clarke', 0, NULL, 'Lecture', '1–6', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This graduate course will explore particular themes, topics, and issues that are of general import to Native American and Indigenous cultures. Topics and aspects will vary, but will usually be broad subjects that cut across fields, regions, periods and cultures. Particular attention will be given to Indigenous expressions of knowledge.', ARRAY[]::TEXT[], NULL),
