    ('NEUS-N 500', 'NEURAL SCIENCE I', '2718', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PY 137C', 'Heather Bradshaw, Cary Lai', 6, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Basic introduction and current trends in cellular neurophysiology, neurocytology, synaptic processes, and neuroanatomy. Laboratory demonstrations. Vertebrate brain dissection and microscopy.', ARRAY[]::TEXT[], NULL),
