    ('NURS-A 103', 'MEDICAL TERMINOLOGY FOR HEALTH PROFESSIONALS', '15035', 'Class Status', 'M Monday 12:00 PM–3:00 PM', 'AH C1020B', 'Jill Evans', 16, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'The primary focus of this course is medical terminology skills including spelling, pronunciation, analysis of root words, prefixes/suffixes, and the correct use of terms when writing or conversing. Review commonly encountered laboratory, radiological, & tests associated with body systems. Students will learn basic anatomy, physiology, and the medical terminology.', ARRAY['Class uses IU eTexts'], NULL),
    ('NURS-B 234', 'PROMOTING HEALTHY POPULATIONS', '7128', 'Closed', 'W Wednesday 1:00 PM–4:00 PM', 'AH C1001X', 'Sonita Ball', 0, NULL, 'Lecture', '4', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on preventive health care and health promotion in individuals, families, and communities considering the influence of culture and lifespan development. Using biophysical, environmental, spiritual, sociocultural and economic determinants of health, students focus on improving health outcomes with individuals, families and communities.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 234', 'PROMOTING HEALTHY POPULATIONS', '12096', 'Closed', 'W Wednesday 8:30 AM–11:30 AM', 'AH C1001X', 'Sonita Ball', 0, NULL, 'Lecture', '4', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on preventive health care and health promotion in individuals, families, and communities considering the influence of culture and lifespan development. Using biophysical, environmental, spiritual, sociocultural and economic determinants of health, students focus on improving health outcomes with individuals, families and communities.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 235', 'PROMOTING HEALTHY POPULATIONS PRACTICUM', '10976', 'Closed', 'Tu Tuesday 12:15 PM–2:15 PM', 'AH C1001Y HD TBA', 'Brittany Black', 0, NULL, 'Laboratory', '1', 'THE HEALTH SCIENCES BUILDING, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Students assess individuals, families and communities, providing needed education, preventive services, and support. Students provide individual and population based care in community based settings, giving consideration to the perspective of those being served.', ARRAY[]::TEXT[], NULL),
