    ('NURS-B 244', 'COMPREHENSIVE HEALTH ASSESSMENT', '2721', 'Closed', 'W Wednesday 1:00 PM–3:00 PM', 'AH C1001Y', 'Patricia Watts', 0, NULL, 'Lecture', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on helping students acquire skills to conduct a comprehensive health assessment, including the physical, psychological, social, functional, and environmental aspects of health. The process of data collection, interpretation, documentation, and dissemination of assessment data will be addressed.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 244', 'COMPREHENSIVE HEALTH ASSESSMENT', '12033', 'Closed', 'M Monday 1:00 PM–3:00 PM', 'AH C1023Z', 'Patricia Watts', 0, NULL, 'Lecture', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on helping students acquire skills to conduct a comprehensive health assessment, including the physical, psychological, social, functional, and environmental aspects of health. The process of data collection, interpretation, documentation, and dissemination of assessment data will be addressed.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 245', 'HEALTH ASSESSMENT: PRACTICUM', '2722', 'Closed', 'F Friday 9:30 AM–2:00 PM', 'AH C2034C', 'Jill Evans', 0, NULL, 'Clinic', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students will have the opportunity to use interview, observation, percussion, palpation, inspection and auscultation in assessing clients across the life span in simulated and actual environments.', ARRAY[]::TEXT[], NULL),
