    ('NURS-B 245', 'HEALTH ASSESSMENT: PRACTICUM', '6745', 'Closed', 'Tu Tuesday 9:30 AM–2:00 PM', 'AH C2034D', 'Pei-Shiun Chang', 0, NULL, 'Clinic', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students will have the opportunity to use interview, observation, percussion, palpation, inspection and auscultation in assessing clients across the life span in simulated and actual environments.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 245', 'HEALTH ASSESSMENT: PRACTICUM', '6746', 'Closed', 'Tu Tuesday 9:30 AM–2:00 PM', 'AH C2034C', 'Samantha Eads, Jill Evans', 0, NULL, 'Clinic', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students will have the opportunity to use interview, observation, percussion, palpation, inspection and auscultation in assessing clients across the life span in simulated and actual environments.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 245', 'HEALTH ASSESSMENT: PRACTICUM', '12094', 'Closed', 'Th Thursday 9:30 AM–2:00 PM', 'AH C2034C', 'Pei-Shiun Chang', 0, NULL, 'Clinic', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students will have the opportunity to use interview, observation, percussion, palpation, inspection and auscultation in assessing clients across the life span in simulated and actual environments.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 245', 'HEALTH ASSESSMENT: PRACTICUM', '12095', 'Closed', 'Th Thursday 9:30 AM–2:00 PM', 'AH C2034D', 'Jamie Lupfer, Erin Wyatt', 0, NULL, 'Clinic', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students will have the opportunity to use interview, observation, percussion, palpation, inspection and auscultation in assessing clients across the life span in simulated and actual environments.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 253', 'PROFESSIONALISM IN COLLABORATIVE PRACTICE', '7092', 'Closed', 'M Monday 8:30 AM–11:30 AM', 'AH C1001X', 'Britney Arce', 0, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students practice communication skills for working with health team members and clients, including self-awareness, interpersonal communication, team skills, and technological communication. Students are introducted to ethics, scope and standards of nursing practice, roles of health team members, components of professional practice and leadership.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 253', 'PROFESSIONALISM IN COLLABORATIVE PRACTICE', '12097', 'Closed', 'W Wednesday 8:30 AM–11:30 AM', 'AH C1001Y', 'Britney Arce', 0, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students practice communication skills for working with health team members and clients, including self-awareness, interpersonal communication, team skills, and technological communication. Students are introducted to ethics, scope and standards of nursing practice, roles of health team members, components of professional practice and leadership.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 304', 'HEALTH POLICY', '5133', 'Class Status', 'Non Standard Session', 'WB WEB', 'April Mouser', 22, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Social, ethical, cultural, economic, and political issues that affect the delivery of health and nursing services globally are critically analyzed. Government and entrepreneurial interests are examined. Emphasis is placed on the impact of policy decisions on professional nursing practice and health services.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 331', 'TRANSITION TO BACCALAUREATE NURSING PRACTICE', '6484', 'Class Status', 'Non Standard Session', 'WB WEB', 'Janice McMahan', 13, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course bridges the nurse to the essential elements of baccalaureate professional practice. Students examine inter and intra professional communication, collaboration, and teamwork to enhance quality patient care. Students explore nursing professional organizations, issues in professional practice, and the impact of lifelong learning on career development.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 331', 'TRANSITION TO BACCALAUREATE NURSING PRACTICE', '6485', 'Class Status', 'Non Standard Session', 'WB WEB', 'Bethany Murray', 19, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course bridges the nurse to the essential elements of baccalaureate professional practice. Students examine inter and intra professional communication, collaboration, and teamwork to enhance quality patient care. Students explore nursing professional organizations, issues in professional practice, and the impact of lifelong learning on career development.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 334', 'TRANSITIONAL CARE OF FAMILIES AND POPULATIONS', '7093', 'Class Status', 'M Monday 1:00 PM–4:00 PM', 'AH C1001Y', 'Ronda Hendricks', 2, 'Lecture', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Using childbearing families as an extensive exemplar, this course focuses on family and community health: community assessment, epidemiology, and intervention with individuals, families, communities and populations. Students address prenatal care, normal and high risk pregnancy and childbirth, newborn care, genetic counseling, care coordination, complementary care, and environmental health.', ARRAY[]::TEXT[], NULL),
