    ('NURS-B 334', 'TRANSITIONAL CARE OF FAMILIES AND POPULATIONS', '13747', 'Closed', 'Tu Tuesday 6:45 AM–7:00 PM', 'HD TBA', 'Brittany Black', 0, 'Clinic', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Using childbearing families as an extensive exemplar, this course focuses on family and community health: community assessment, epidemiology, and intervention with individuals, families, communities and populations. Students address prenatal care, normal and high risk pregnancy and childbirth, newborn care, genetic counseling, care coordination, complementary care, and environmental health.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 403', 'AGING WITH DIGNITY', '5299', 'Class Status', 'Non Standard Session', 'WB WEB', 'Stephanie Baranko Lincoln', 24, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course promotes a holistic approach to persons in the later years of life. Death and dying, legal and ethical issues, family care giving, and future challenges will be discussed in the context of best practices as outlined by the John A. Hartford foundation; Institute for Geriatric nursing.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 404', 'INFORMATICS', '5389', 'Class Status', 'Non Standard Session', 'WB WEB', 'Kristen Mattox', 8, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course addresses nursing informatics: state of the science and issues for research, development, and practice. It clarifies concepts of nursing, technology, and information management; and comprises theory, practice, and the social and ethical issues in nursing and health care informatics.', ARRAY[]::TEXT[], NULL),
    ('NURS-B 444', 'NURSING INTENSIVE: MANAGING HEALTH AND ILLNESS ACROSS CARE ENVIRONMENTS', '7094', 'Class Status', 'F Friday 8:00 AM–12:05 PM', 'AH C1001X', 'Kim Decker', 3, 'Lecture', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students study a focused clinical area of concern for nursing, exploring the ways in which culture, health disparity, transitions between care environments, and health policy impact care for an aggregate, population, or specialty. Immersed in a care environment, students gain relevant clinical knowledge as well as an understanding of the aggregate health concerns.', ARRAY['Class uses IU eTexts'], NULL),
