    ('NURS-B 444', 'NURSING INTENSIVE: MANAGING HEALTH AND ILLNESS ACROSS CARE ENVIRONMENTS', '30165', 'Closed', 'Th Thursday 7:00 AM–9:00 PM', 'HD TBA', 'Anna Olson', 0, 'Clinic', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students study a focused clinical area of concern for nursing, exploring the ways in which culture, health disparity, transitions between care environments, and health policy impact care for an aggregate, population, or specialty. Immersed in a care environment, students gain relevant clinical knowledge as well as an understanding of the aggregate health concerns.', ARRAY['Class uses IU eTexts'], NULL),
    ('NURS-H 355', 'DATA ANALYSIS FOR PRACTICE AND RESEARCH', '10562', 'Class Status', 'M Monday 9:00 AM–12:00 PM', 'AH C1020Y', 'Amy Wonder', 2, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Introduces nursing and other health science students to the basic concepts and techniques of data analysis needed in professional health care practice. Principles of measurement, data summarization, and univariate and bivariate statistics are examined. Differences in types of qualitative data and methods by which these types of data can be interpreted are also explored. Emphasis is placed on the application of fundamental concepts to real world situations in client care.', ARRAY[]::TEXT[], NULL),
    ('NURS-H 355', 'DATA ANALYSIS FOR PRACTICE AND RESEARCH', '5135', 'Class Status', 'Non Standard Session', 'WB WEB', 'Kerri Getz', 19, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Introduces nursing and other health science students to the basic concepts and techniques of data analysis needed in professional health care practice. Principles of measurement, data summarization, and univariate and bivariate statistics are examined. Differences in types of qualitative data and methods by which these types of data can be interpreted are also explored. Emphasis is placed on the application of fundamental concepts to real world situations in client care.', ARRAY[]::TEXT[], NULL),
    ('NURS-H 355', 'DATA ANALYSIS FOR PRACTICE AND RESEARCH', '13197', 'Closed', 'M Monday 1:00 PM–4:00 PM', 'AH C1020Y', 'Andrea Tanner', 0, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Introduces nursing and other health science students to the basic concepts and techniques of data analysis needed in professional health care practice. Principles of measurement, data summarization, and univariate and bivariate statistics are examined. Differences in types of qualitative data and methods by which these types of data can be interpreted are also explored. Emphasis is placed on the application of fundamental concepts to real world situations in client care.', ARRAY[]::TEXT[], NULL),
