    ('NURS-H 403', 'NURSING CLINICAL INTENSIVE', '8654', 'Class Status', 'Tu Tuesday 7:00 AM–8:30 PM', 'HD TBA', 'Kristen Mattox', 1, NULL, 'Clinic', '2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This intensive clinical course, comprised of clinical and simulation experiences, incorporates skills, knowledge and behaviors consistent with the nursing process. Students will refine clinical skills and master the nursing process. Attention is focused on developing clinical reasoning, demonstration of critical thinking and competent nursing practice at an advanced level.', ARRAY[]::TEXT[], NULL),
