    ('NURS-H 499', 'HONORS RESEARCH', '3066', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'After completion of H399, students pursuing departmental honors will work with a faculty member to implement the study designed in H399. After data collection and analysis, students will prepare a manuscript of the study suitable for publication. This is an individually negotiated course requiring faculty approval prior to enrollment.', ARRAY[]::TEXT[], NULL),
    ('NURS-H 499', 'HONORS RESEARCH', '5132', 'Class Status', NULL, NULL, 'Amy Wonder', 10, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'After completion of H399, students pursuing departmental honors will work with a faculty member to implement the study designed in H399. After data collection and analysis, students will prepare a manuscript of the study suitable for publication. This is an individually negotiated course requiring faculty approval prior to enrollment.', ARRAY[]::TEXT[], NULL),
    ('NURS-H 499', 'HONORS RESEARCH', '5420', 'Class Status', NULL, NULL, 'Deanna Reising', 10, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'After completion of H399, students pursuing departmental honors will work with a faculty member to implement the study designed in H399. After data collection and analysis, students will prepare a manuscript of the study suitable for publication. This is an individually negotiated course requiring faculty approval prior to enrollment.', ARRAY[]::TEXT[], NULL),
    ('NURS-K 301', 'COMPLEMENTARY HEALTH THERAPIES', '8822', 'Class Status', 'Non Standard Session', 'WB WEB', 'Cindy Hill', 23, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is designed to introduce the student to non-mainstream health care therapies. The course will serve as an introduction to a variety of therapies, including healing touch, guided imagery, hypnosis, acupuncture, aromatherapy, reflexology and massage, to name a few.', ARRAY[]::TEXT[], NULL),
    ('NURS-K 310', 'SELF MANAGEMENT AND HEALTH PROMOTION', '29308', 'Class Status', 'Non Standard Session', 'WB WEB', 'Teresa Miller', 16, NULL, 'Discussion', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course explores self-management and health promotion based on the Eight Dimensions of Wellness from an interprofessional perspective. This course unfolds as modules, each focusing on a dimension of wellness. Students will examine eight areas of wellness: occupational, social, financial, physical, emotional, environmental, spiritual, and intellectual wellness.', ARRAY[]::TEXT[], NULL),
    ('NURS-K 434', 'CURRENT TRENDS IN GLOBAL HEALTH NURSING', '5651', 'Class Status', 'Non Standard Session', 'WB WEB', 'Marian Gilhooly', 21, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This dynamic course provides learning opportunities for global health issues that contribute to health disparities and ways in which healthcare workers are striving to address them. Priority is given to healthcare issues highlighted by the World Health Organization including infectious and chronic illness, women''s health, environmental impacts and disaster response.', ARRAY[]::TEXT[], NULL),
    ('NURS-K 492', 'NURSING ELECTIVE', '34787', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'JH 009', 'Bethany Murray', 35, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Opportunity for the student to pursue study in an area of interest.', ARRAY['Class uses IU eTexts'], NULL),
    ('NURS-L 430', 'LEADERSHIP IN HEALTH CARE DELIVERY', '6715', 'Class Status', 'M Monday 9:00 AM–12:00 PM', 'AH C1001Y', 'Dena Klineline', 1, 'Lecture', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on development of effective leadership skills relevant in health care systems. Students examine health policy, study information management, and employ processes that result in exceptional organizational outcomes. Students use healthcare data and research evidence in quality improvement and change initiatives.', ARRAY[]::TEXT[], NULL),
    ('NURS-L 430', 'LEADERSHIP IN HEALTH CARE DELIVERY', '6716', 'Class Status', 'Tu Tuesday 7:00 AM–8:00 PM', 'HD TBA', 'Courtney Degener', 1, 'Clinic', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on development of effective leadership skills relevant in health care systems. Students examine health policy, study information management, and employ processes that result in exceptional organizational outcomes. Students use healthcare data and research evidence in quality improvement and change initiatives.', ARRAY[]::TEXT[], NULL),
    ('NURS-L 430', 'LEADERSHIP IN HEALTH CARE DELIVERY', '7683', 'Closed', 'Tu Tuesday 7:00 AM–8:00 PM', 'HD TBA', 'Deanna Reising', 0, 'Clinic', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on development of effective leadership skills relevant in health care systems. Students examine health policy, study information management, and employ processes that result in exceptional organizational outcomes. Students use healthcare data and research evidence in quality improvement and change initiatives.', ARRAY[]::TEXT[], NULL),
    ('NURS-L 430', 'LEADERSHIP IN HEALTH CARE DELIVERY', '7684', 'Closed', 'Th Thursday 7:00 AM–8:00 PM', 'HD TBA', 'Courtney Degener', 0, 'Clinic', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on development of effective leadership skills relevant in health care systems. Students examine health policy, study information management, and employ processes that result in exceptional organizational outcomes. Students use healthcare data and research evidence in quality improvement and change initiatives.', ARRAY[]::TEXT[], NULL),
    ('NURS-L 430', 'LEADERSHIP IN HEALTH CARE DELIVERY', '7685', 'Closed', 'Th Thursday 7:00 AM–8:00 PM', 'HD TBA', 'Hanna Raber', 0, 'Clinic', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on development of effective leadership skills relevant in health care systems. Students examine health policy, study information management, and employ processes that result in exceptional organizational outcomes. Students use healthcare data and research evidence in quality improvement and change initiatives.', ARRAY[]::TEXT[], NULL),
    ('NURS-L 430', 'LEADERSHIP IN HEALTH CARE DELIVERY', '30173', 'Closed', 'Tu Tuesday 7:00 AM–8:00 PM', 'HD TBA', 'Dena Klineline', 0, 'Clinic', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on development of effective leadership skills relevant in health care systems. Students examine health policy, study information management, and employ processes that result in exceptional organizational outcomes. Students use healthcare data and research evidence in quality improvement and change initiatives.', ARRAY[]::TEXT[], NULL),
    ('NURS-L 430', 'LEADERSHIP IN HEALTH CARE DELIVERY', '30174', 'Closed', 'Th Thursday 7:00 AM–8:30 PM', 'HD TBA', 'Courtney Degener', 0, 'Clinic', 'Lecture', '5', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'This course focuses on development of effective leadership skills relevant in health care systems. Students examine health policy, study information management, and employ processes that result in exceptional organizational outcomes. Students use healthcare data and research evidence in quality improvement and change initiatives.', ARRAY[]::TEXT[], NULL),
    ('NURS-R 375', 'NURSING RESEARCH AND EVIDENCE-BASED PRACTICE', '7827', 'Class Status', 'Non Standard Session', 'WB WEB', 'Stephanie Pratt', 21, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on nursing research and evidence-based practice. Students develop skills in retrieving and appraising literature relevant to clinical problems, understanding the research process, and critiquing evidence from research publications and other sources to inform evidence-based nursing practice.', ARRAY[]::TEXT[], NULL),
    ('NURS-R 470', 'CLINICAL BACCALAUREATE NURSING CAPSTONE', '6494', 'Class Status', 'Non Standard Session', 'WB WEB', 'Dena Klineline', 20, NULL, 'Clinic', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course allows students to synthesize knowledge and skills learned in the baccalaureate program and to demonstrate competencies consistent with program outcomes and to refine their nursing practice skills. Students will plan and organize learning experiences, design a project, and practice professional nursing in a safe and effective manner.', ARRAY[]::TEXT[], NULL),
    ('NURS-R 470', 'CLINICAL BACCALAUREATE NURSING CAPSTONE', '6496', 'Class Status', 'Non Standard Session', 'WB WEB', 'Roxie Barnes', 23, NULL, 'Clinic', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course allows students to synthesize knowledge and skills learned in the baccalaureate program and to demonstrate competencies consistent with program outcomes and to refine their nursing practice skills. Students will plan and organize learning experiences, design a project, and practice professional nursing in a safe and effective manner.', ARRAY[]::TEXT[], NULL),
    ('NURS-S 410', 'EMERGENCY PREPAREDNESS AND DISASTER RESPONSE', '7611', 'Class Status', 'Non Standard Session', 'WB WEB', 'Maria Hines', 23, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on the theoretical and practical perspectives of disaster response and emergency management for nursing professionals. Students will explore disaster/ emergency response preparedness, leadership principles, decision-making, and recovery training measures for health care providers devoted to supporting community disaster resilience.', ARRAY[]::TEXT[], NULL),
    ('NURS-S 420', 'CARE COORDINATION IN TRANSITIONS OF CARE', '7659', 'Class Status', 'Non Standard Session', 'WB WEB', 'Susan Plough', 24, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Students will synthesize knowledge and skills relevant to care coordination to ensure smooth care transition. Students will develop an understanding of the role of the RN as a member of a interprofessional team, as well as options for the most appropriate care setting for an individual patient.', ARRAY[]::TEXT[], NULL),
    ('NURS-S 474', 'APPLIED HEALTH CARE ETHICS', '4834', 'Class Status', 'W Wednesday 1:00 PM–4:00 PM', 'AH C1020Y', 'Hanna Raber', 3, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Building on the ANA Code of Ethics, this course explores the nurse''s role in ethical clinical practice, academic work, health policy, and research conduct, focusing particularly on the advocacy role of the nurse. Common ethical problems are discussed and strategies for resolution are applied.', ARRAY[]::TEXT[], NULL),
    ('NURS-S 474', 'APPLIED HEALTH CARE ETHICS', '7682', 'Class Status', 'M Monday 1:00 PM–4:00 PM', 'AH C1001X', 'Alicia Marte', 1, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Building on the ANA Code of Ethics, this course explores the nurse''s role in ethical clinical practice, academic work, health policy, and research conduct, focusing particularly on the advocacy role of the nurse. Common ethical problems are discussed and strategies for resolution are applied.', ARRAY[]::TEXT[], NULL),
    ('NURS-S 474', 'APPLIED HEALTH CARE ETHICS', '5136', 'Class Status', 'Non Standard Session', 'WB WEB', 'Paula Baumann', 21, NULL, 'Lecture', '3', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Building on the ANA Code of Ethics, this course explores the nurse''s role in ethical clinical practice, academic work, health policy, and research conduct, focusing particularly on the advocacy role of the nurse. Common ethical problems are discussed and strategies for resolution are applied.', ARRAY[]::TEXT[], NULL),
    ('NURS-S 475', 'A MULTISYSTEM APPROACH TO THE HEALTH OF THE COMMUNITY: RNBSN', '5123', 'Class Status', 'Non Standard Session', 'WB WEB', 'Alicia Marte', 8, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Basic epidemiological principles and community health nursing models are applied in collaboration with diverse groups. Disease prevention strategies are applied to individuals and populations to promote health students apply the concepts of community assessment, disease prevention and health promotion to plan, implement, and evaluate interventions for populations in the community.', ARRAY[]::TEXT[], NULL),
    ('NURS-S 487', 'NURSING MANAGEMENT:RNBSN', '5395', 'Class Status', 'Non Standard Session', 'WB WEB', 'Hanna Raber', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on development of management skills assumed by professional nurses, including delegation of responsibilities, networking, and facilitation of groups, conflict resolution, leadership, case management, and collaboration. Concepts addressed include organizational structure, delivers systems, change, managing quality and performance, budgeting and resource allocation, staffing, scheduling, evaluation and career development.', ARRAY[]::TEXT[], NULL),
    ('NURS-S 488', 'SYNTHESIS FOR PROFESSIONAL NURSING PRACTICE', '8608', 'Class Status', 'F Friday 1:00 PM–3:00 PM', 'AH C1001X', 'Patricia Watts', 3, NULL, 'Seminar', '2', 'THE HEALTH SCIENCES BUILDING', ARRAY[]::TEXT[], 'Students integrate knowledge and skills acquired throughout the program: critical thinking, information technology, cultural competence, care coordination, leadership, collaboration, and communication skills. Students demonstrate competence in evidence-based practice and quality and safety initiatives, as achieved in a complex and changing health care environment. Students begin the transition to professional practice.', ARRAY['Class uses IU eTexts'], NULL),
    ('OPT-V 469', 'SELECTED STUDIES', '12952', 'Class Status', NULL, NULL, 'Catherine Cheng', 5, NULL, 'Lecture', '1–8', NULL, ARRAY[]::TEXT[], 'Items of current scientific interest. Consideration given to student''s special interests. May include writing of abstracts and reviews of current visual science literature.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 501', 'INTEGRATIVE OPTOMETRY 1', '5574', 'Class Status', 'M Monday 10:00 AM–11:30 AM', 'HD TBA', 'Shirin Hassan', 10, NULL, 'Laboratory', '2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'This course sequence is offered over two semesters. Overall goal is to provide an integrated perspective of optometry in the paradigms of problem-based learning (PBL) and interprofessional education (IPE).', ARRAY[]::TEXT[], NULL),
    ('OPT-V 502', 'INTEGRATED OPTOMETRY 2', '5575', 'Class Status', 'M Monday 10:00 AM–11:30 AM', 'HD TBA', 'Shirin Hassan', 10, NULL, 'Laboratory', '2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Overall goal is to provide an integrates perspective of Optometry in the paradigm of problem-based learning (PBL). The problems will be clinical cases which relate to the contents of courses taught contemporaneously in optics, biomedical and ocular biology modules.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 521', 'GEOMETRIC AND VISUAL OPTICS 1', '3545', 'Closed', 'Tu Tuesday 10:00 AM–10:50 AM', 'OP 105 OP 105', 'Nikole Himebaugh, Patrice Tankam', 0, 'Lecture', 'Lecture', '4', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Fundaments of geometric and physical optics. Optical analysis of myopia, hyperopia and astigmatism. Components of the eyes and their optical properties. Clinical instrumentation for optical measurement and diagnosis of eyes.', ARRAY[]::TEXT[], NULL),
