    ('OPT-V 521', 'GEOMETRIC AND VISUAL OPTICS 1', '11915', 'Closed', 'Th Thursday 4:30 PM–5:50 PM', 'OP 104', 'Nikole Himebaugh, Patrice Tankam', 0, 'Laboratory', 'Lecture', '4', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Fundaments of geometric and physical optics. Optical analysis of myopia, hyperopia and astigmatism. Components of the eyes and their optical properties. Clinical instrumentation for optical measurement and diagnosis of eyes.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 521', 'GEOMETRIC AND VISUAL OPTICS 1', '11916', 'Closed', 'F Friday 2:00 PM–3:20 PM', 'OP 104', 'Nikole Himebaugh, Patrice Tankam', 0, 'Laboratory', 'Lecture', '4', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Fundaments of geometric and physical optics. Optical analysis of myopia, hyperopia and astigmatism. Components of the eyes and their optical properties. Clinical instrumentation for optical measurement and diagnosis of eyes.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 540', 'OCCULAR ANATOMY AND PHYSIOLOGY', '3550', 'Closed', 'M Monday 12:00 PM–12:50 PM', 'OP 111 OP 111', 'Stephanie Klemencic, Hin Cheung, Tracy Nguyen', 0, 'Lecture', 'Lecture', '4', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Provides a detailed understanding of the structure and function of the eye as well as the orbits, head, and brain as it relates to vision and ocular functions. Gross anatomy, histology, and cellular biochemistry, as well as adnexa, muscles, skull, blood supply, and nervous system will be discussed.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 540', 'OCCULAR ANATOMY AND PHYSIOLOGY', '3551', 'Closed', 'Tu Tuesday 1:00 PM–2:50 PM', 'OP 102', 'Stephanie Klemencic, Hin Cheung, Tracy Nguyen', 0, 'Laboratory', 'Lecture', '4', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Provides a detailed understanding of the structure and function of the eye as well as the orbits, head, and brain as it relates to vision and ocular functions. Gross anatomy, histology, and cellular biochemistry, as well as adnexa, muscles, skull, blood supply, and nervous system will be discussed.', ARRAY[]::TEXT[], NULL),
