    ('OPT-V 540', 'OCCULAR ANATOMY AND PHYSIOLOGY', '3553', 'Closed', 'Tu Tuesday 5:00 PM–6:50 PM', 'OP 102', 'Stephanie Klemencic, Hin Cheung, Tracy Nguyen', 0, 'Laboratory', 'Lecture', '4', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Provides a detailed understanding of the structure and function of the eye as well as the orbits, head, and brain as it relates to vision and ocular functions. Gross anatomy, histology, and cellular biochemistry, as well as adnexa, muscles, skull, blood supply, and nervous system will be discussed.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 540', 'OCCULAR ANATOMY AND PHYSIOLOGY', '7923', 'Closed', 'W Wednesday 12:30 PM–2:20 PM', 'OP 102', 'Stephanie Klemencic, Hin Cheung, Tracy Nguyen', 0, 'Laboratory', 'Lecture', '4', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Provides a detailed understanding of the structure and function of the eye as well as the orbits, head, and brain as it relates to vision and ocular functions. Gross anatomy, histology, and cellular biochemistry, as well as adnexa, muscles, skull, blood supply, and nervous system will be discussed.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 542', 'FUNDAMENTALS OF SYSTEMIC HEALTH AND DISEASE 1', '3554', 'Closed', 'M Monday 8:00 AM–9:50 AM', 'OP 111 OP 105 OP 111', 'Catherine Cheng, Nicholas Port', 0, 'Lecture', 'Lecture', '5.5', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'This is the first of a two-semester sequence addressing basic science information organized into specific organ systems. This course covers common processes: basic biochemistry, cell and molecular biology, fundamentals of physiology, immunology/infection, oncology, and neurology. Organ systems covered include central nervous system, skin and epithelium, and musculoskeletal.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 542', 'FUNDAMENTALS OF SYSTEMIC HEALTH AND DISEASE 1', '3555', 'Closed', 'Th Thursday 11:00 AM–12:20 PM', 'OP 102', 'Catherine Cheng', 0, 'Laboratory', 'Lecture', '5.5', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'This is the first of a two-semester sequence addressing basic science information organized into specific organ systems. This course covers common processes: basic biochemistry, cell and molecular biology, fundamentals of physiology, immunology/infection, oncology, and neurology. Organ systems covered include central nervous system, skin and epithelium, and musculoskeletal.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 542', 'FUNDAMENTALS OF SYSTEMIC HEALTH AND DISEASE 1', '3556', 'Closed', 'Th Thursday 12:30 PM–1:50 PM', 'OP 102', 'Catherine Cheng', 0, 'Laboratory', 'Lecture', '5.5', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'This is the first of a two-semester sequence addressing basic science information organized into specific organ systems. This course covers common processes: basic biochemistry, cell and molecular biology, fundamentals of physiology, immunology/infection, oncology, and neurology. Organ systems covered include central nervous system, skin and epithelium, and musculoskeletal.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 542', 'FUNDAMENTALS OF SYSTEMIC HEALTH AND DISEASE 1', '3557', 'Closed', 'Th Thursday 2:00 PM–3:20 PM', 'OP 102', 'Catherine Cheng', 0, 'Laboratory', 'Lecture', '5.5', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'This is the first of a two-semester sequence addressing basic science information organized into specific organ systems. This course covers common processes: basic biochemistry, cell and molecular biology, fundamentals of physiology, immunology/infection, oncology, and neurology. Organ systems covered include central nervous system, skin and epithelium, and musculoskeletal.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 542', 'FUNDAMENTALS OF SYSTEMIC HEALTH AND DISEASE 1', '36384', 'Closed', 'Th Thursday 3:30 PM–4:50 PM', 'OP 102', 'Catherine Cheng', 0, 'Laboratory', 'Lecture', '5.5', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'This is the first of a two-semester sequence addressing basic science information organized into specific organ systems. This course covers common processes: basic biochemistry, cell and molecular biology, fundamentals of physiology, immunology/infection, oncology, and neurology. Organ systems covered include central nervous system, skin and epithelium, and musculoskeletal.', ARRAY[]::TEXT[], NULL),
    ('OPT-V 550', 'CLINICAL SCIENCES I', '3558', 'Closed', 'M Monday 10:00 AM–11:50 AM', 'OP 111', 'Todd Peabody, Michael Mc Veigh', 0, 'Lecture', 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'Introduction to clinical history and interview techniques, health history content, and medical record documentation as applied to the optometric setting; optometric and medical terminology, interview techniques for special populations, legal aspects of medical records, differential diagnosis of visual symptoms, introduction to physical assessment slit lamp biomicroscopy and opnthalmoscopy.', ARRAY[]::TEXT[], NULL),
